args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?manga ?mangaLabel ?copiesSold
WHERE {
  {
    SELECT ?manga (AVG(xsd:integer(?sold)) AS ?copiesSold)
    WHERE {
      ?manga wdt:P31/wdt:P279* wd:Q7788 .
      ?manga wdt:P136 wd:Q231302 .
      ?manga wdt:P1602 ?sold .
      FILTER(xsd:integer(?sold) > 0)
    }
    GROUP BY ?manga
    ORDER BY DESC(?copiesSold)
    LIMIT 30
  }
  MINUS {
    ?manga wdt:P136 ?genre .
    VALUES ?genre { 
      wd:Q334741  # Martial Arts
      wd:Q165598   # Action
      wd:Q20790659 # Battle manga
    }
  }
  ?manga rdfs:label ?mangaLabel .
  FILTER(LANG(?mangaLabel) = "en")
}
ORDER BY DESC(?copiesSold)
